import androidx.appcompat.app.AppCompatActivity;

import com.courassistant.java.R;
import com.courassistant.java.databinding.ActivityPdfWebviewBinding;
import com.courassistant.java.model.CourtDocument;
import com.courassistant.java.utils.DeduplicationHelper;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import java.util.HashSet;
import java.util.Set;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

/**
 * WebView PDF 下载Activity
 * 功能：
 * 1. 加载法院网页（支持JavaScript）
 * 2. 拦截PDF下载请求
 * 3. 显示下载进度和提示
 * 4. 自动下载PDF文件
 * 5. 下载完成后保存到数据库
 * 6. PDF下载去重
 */
public class PdfWebViewActivity extends AppCompatActivity {

    private static final String TAG = "PdfWebViewActivity";
    private static final String PDF_MIME_TYPE = "application/pdf";

    private ActivityPdfWebviewBinding binding;
    private WebView webView;
    private ProgressDialog downloadProgressDialog;
    private ExecutorService downloadExecutor;

    // 已下载的PDF文件集合（用于去重）
    private Set<String> downloadedPdfs = new HashSet<>();
    // 待处理的PDF文档（下载完成后解析）
    private final java.util.List<CourtDocument> pendingDocuments = new java.util.ArrayList<>();

    // 数据库回调接口
    public interface OnDocumentDownloadedListener {
        void onDocumentDownloaded(CourtDocument document);
    }

    private OnDocumentDownloadedListener documentListener;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityPdfWebviewBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        webView = binding.webView;
        downloadExecutor = Executors.newSingleThreadExecutor();

        setupWebView();
        setupProgressDialog();
        loadInitialUrl();
    }

    /**
     * 设置WebView
     */
    private void setupWebView() {
        WebSettings settings = webView.getSettings();

        // 启用JavaScript（法院网页通常需要）
        settings.setJavaScriptEnabled(true);
        settings.setDomStorageEnabled(true);
        settings.setDatabaseEnabled(true);

        // 支持缩放
        settings.setSupportZoom(true);
        settings.setBuiltInZoomControls(true);
        settings.setDisplayZoomControls(false);

        // 自适应屏幕
        settings.setUseWideViewPort(true);
        settings.setLoadWithOverviewMode(true);

        // 支持内容重新布局
        settings.setLayoutAlgorithm(WebSettings.LayoutAlgorithm.SINGLE_COLUMN);

        // 支持文件访问
        settings.setAllowFileAccess(true);
        settings.setAllowContentAccess(true);

        // 缓存设置
        settings.setCacheMode(WebSettings.LOAD_DEFAULT);

        // 启用混合内容模式（HTTPS页面加载HTTP资源）
        settings.setMixedContentMode(WebSettings.MIXED_CONTENT_ALWAYS_ALLOW);

        // 设置WebViewClient
        webView.setWebViewClient(new CourtWebViewClient());

        // 设置WebChromeClient（处理进度条等）
        webView.setWebChromeClient(new WebChromeClient() {
            @Override
            public void onProgressChanged(WebView view, int newProgress) {
                super.onProgressChanged(view, newProgress);
                // 可以在这里显示页面加载进度
            }

            @Override
            public void onReceivedTitle(WebView view, String title) {
                super.onReceivedTitle(view, title);
                // 可以更新页面标题
            }
        });

        // 设置下载监听器
        webView.setDownloadListener(new PdfDownloadListener());
    }

    /**
     * 设置进度对话框
     */
    private void setupProgressDialog() {
        downloadProgressDialog = new ProgressDialog(this);
        downloadProgressDialog.setMessage("正在下载PDF...");
        downloadProgressDialog.setProgressStyle(ProgressDialog.STYLE_HORIZONTAL);
        downloadProgressDialog.setCancelable(false);
        downloadProgressDialog.setButton(DialogInterface.BUTTON_NEGATIVE, "取消",
                (dialog, which) -> {
                    // 取消下载（需要实现取消逻辑）
                    dialog.dismiss();
                });
    }

    /**
     * 加载初始URL
     * 从Intent获取URL，或使用默认URL
     */
    private void loadInitialUrl() {
        String url = getIntent().getStringExtra("url");
        if (url == null || url.isEmpty()) {
            url = "https://www.chinacourt.org"; // 默认法院网站
        }

        webView.loadUrl(url);
    }

    /**
     * 自定义WebViewClient - 拦截资源请求
     */
    private class CourtWebViewClient extends WebViewClient {

        @Override
        public boolean shouldOverrideUrlLoading(WebView view, WebResourceRequest request) {
            String url = request.getUrl().toString();

            // 检查是否是PDF链接
            if (isPdfUrl(url)) {
                showPdfDownloadDialog(url);
                return true;
            }

            return false;
        }

        @Override
        public boolean shouldOverrideUrlLoading(WebView view, String url) {
            // 兼容旧版本
            if (isPdfUrl(url)) {
                showPdfDownloadDialog(url);
                return true;
            }
            return false;
        }

        @Override
        public void onPageStarted(WebView view, String url, Bitmap favicon) {
            super.onPageStarted(view, url, favicon);
            // 页面开始加载
        }

        @Override
        public void onPageFinished(WebView view, String url) {
            super.onPageFinished(view, url);
            // 页面加载完成
        }

        /**
         * 拦截资源请求（可以在这里处理AJAX请求等）
         */
        @Override
        public WebResourceResponse shouldInterceptRequest(WebView view, WebResourceRequest request) {
            String url = request.getUrl().toString();

            // 如果是PDF请求，可以在这里处理
            // if (isPdfUrl(url)) {
            //     // 处理PDF下载
            // }

            return super.shouldInterceptRequest(view, request);
        }
    }

    /**
     * 自定义下载监听器
     */
    private class PdfDownloadListener implements DownloadListener {

        @Override
        public void onDownloadStart(String url, String userAgent,
                                    String contentDisposition, String mimetype,
                                    long contentLength) {

            Log.d(TAG, "Download started: " + url);
            Log.d(TAG, "Content-Type: " + mimetype);

            // 检查是否是PDF
            if (PDF_MIME_TYPE.equals(mimetype) || isPdfUrl(url)) {
                // 提取文件名
                String fileName = extractFileNameFromUrl(url, contentDisposition);

                // 显示下载确认对话框
                showPdfDownloadDialog(url, fileName, contentLength);
            } else {
                // 其他类型文件，使用系统下载管理器
                showSystemDownloadDialog(url, userAgent, contentDisposition, mimetype);
            }
        }
    }

    /**
     * 显示PDF下载确认对话框
     */
    private void showPdfDownloadDialog(String url) {
        String fileName = extractFileNameFromUrl(url, null);
        showPdfDownloadDialog(url, fileName, -1);
    }

    private void showPdfDownloadDialog(String url, String fileName, long fileSize) {
        AlertDialog.Builder builder = new AlertDialog.Builder(this);
        builder.setTitle("发现PDF文档");
        builder.setMessage("是否下载此PDF文件？\n\n文件名：" + fileName +
                (fileSize > 0 ? "\n大小：" + formatFileSize(fileSize) : ""));

        builder.setPositiveButton("下载", (dialog, which) -> {
            startDownload(url, fileName);
        });

        builder.setNegativeButton("取消", null);
        builder.setNeutralButton("下载全部PDF", (dialog, which) -> {
            // 下载页面中所有PDF（需要实现扫描逻辑）
            scanAndDownloadAllPdfs();
        });

        builder.show();
    }

    /**
     * 开始下载PDF
     */
    private void startDownload(String url, String fileName) {
        // 检查是否已下载
        if (downloadedPdfs.contains(fileName)) {
            Toast.makeText(this, "该文件已下载", Toast.LENGTH_SHORT).show();
            return;
        }

        downloadExecutor.execute(() -> {
            downloadPdf(url, fileName);
        });
    }

    /**
     * 下载PDF文件
     */
    private void downloadPdf(String urlString, String fileName) {
        HttpURLConnection connection = null;
        InputStream inputStream = null;
        FileOutputStream outputStream = null;

        try {
            URL url = new URL(urlString);
            connection = (HttpURLConnection) url.openConnection();

            // 设置请求头
            connection.setRequestMethod("GET");
            connection.setConnectTimeout(30000);
            connection.setReadTimeout(30000);

            // 携带Cookie（如果需要登录）
            String cookies = CookieManager.getInstance().getCookie(urlString);
            if (cookies != null) {
                connection.setRequestProperty("Cookie", cookies);
            }

            connection.connect();

            int responseCode = connection.getResponseCode();
            if (responseCode != HttpURLConnection.HTTP_OK) {
                runOnUiThread(() -> {
                    Toast.makeText(this, "下载失败：HTTP " + responseCode,
                            Toast.LENGTH_SHORT).show();
                });
                return;
            }

            // 获取文件大小
            final long fileSize = connection.getContentLength();
            String contentDisposition = connection.getHeaderField("Content-Disposition");

            // 如果没有提供文件名，尝试从Content-Disposition中提取
            if (TextUtils.isEmpty(fileName)) {
                fileName = extractFileNameFromUrl(urlString, contentDisposition);
            }

            // 确保文件名以.pdf结尾
            if (!fileName.toLowerCase().endsWith(".pdf")) {
                fileName += ".pdf";
            }

            // 更新进度对话框
            runOnUiThread(() -> {
                downloadProgressDialog.setMessage("正在下载：" + fileName);
                downloadProgressDialog.setMax((int) fileSize);
                downloadProgressDialog.setProgress(0);
                downloadProgressDialog.show();
            });

            inputStream = connection.getInputStream();
            File outputFile = getPdfFile(fileName);
            outputStream = new FileOutputStream(outputFile);

            byte[] buffer = new byte[8192];
            int bytesRead;
            long totalBytesRead = 0;
            int lastProgress = 0;

            while ((bytesRead = inputStream.read(buffer)) != -1) {
                outputStream.write(buffer, 0, bytesRead);
                totalBytesRead += bytesRead;

                // 更新进度
                if (fileSize > 0) {
                    final int progress = (int) ((totalBytesRead * 100) / fileSize);
                    if (progress - lastProgress >= 5) { // 每5%更新一次
                        runOnUiThread(() -> {
                            downloadProgressDialog.setProgress(progress);
                        });
                        lastProgress = progress;
                    }
                }
            }

            outputStream.flush();

            // 下载成功
            final String finalFileName = fileName;
            final String filePath = outputFile.getAbsolutePath();
            final long finalFileSize = totalBytesRead;

            runOnUiThread(() -> {
                downloadProgressDialog.dismiss();
                downloadedPdfs.add(finalFileName);

                Toast.makeText(this, "下载成功：" + finalFileName,
                        Toast.LENGTH_LONG).show();

                // 保存到数据库
                saveDownloadedDocument(finalFileName, filePath, finalFileSize, urlString);
            });

        } catch (Exception e) {
            Log.e(TAG, "下载PDF失败", e);
            runOnUiThread(() -> {
                downloadProgressDialog.dismiss();
                Toast.makeText(this, "下载失败：" + e.getMessage(),
                        Toast.LENGTH_LONG).show();
            });
        } finally {
            try {
                if (inputStream != null) inputStream.close();
                if (outputStream != null) outputStream.close();
                if (connection != null) connection.disconnect();
            } catch (IOException e) {
                Log.e(TAG, "关闭流失败", e);
            }
        }
    }

    /**
     * 获取PDF文件保存路径
     */
    private File getPdfFile(String fileName) {
        // 使用应用专属目录
        File pdfDir = new File(getExternalFilesDir(Environment.DIRECTORY_DOCUMENTS), "CourtPDFs");
        if (!pdfDir.exists()) {
            pdfDir.mkdirs();
        }

        // 如果文件已存在，添加序号
        File file = new File(pdfDir, fileName);
        if (file.exists()) {
            String baseName = fileName.substring(0, fileName.lastIndexOf('.'));
            String extension = fileName.substring(fileName.lastIndexOf('.'));
            int counter = 1;
            while (file.exists()) {
                file = new File(pdfDir, baseName + "_" + counter + extension);
                counter++;
            }
        }

        return file;
    }

    /**
     * 保存下载的文档到数据库
     */
    private void saveDownloadedDocument(String fileName, String filePath, long fileSize, String downloadUrl) {
        CourtDocument document = new CourtDocument();
        document.setFileName(fileName);
        document.setFilePath(filePath);
        document.setFileSize(fileSize);
        document.setFileType("PDF");
        document.setDownloadUrl(downloadUrl);
        document.setParseStatus(CourtDocument.PARSE_STATUS_PENDING);

        // 检查是否是传票
        document.setSummons(document.isSummonsByFileName());

        // 通过回调通知外部保存
        if (documentListener != null) {
            documentListener.onDocumentDownloaded(document);
        } else {
            // 如果没有设置监听器，添加到待处理列表
            pendingDocuments.add(document);
            Log.d(TAG, "文档已添加到待处理列表，请设置documentListener来处理");
        }
    }

    /**
     * 从URL中提取文件名
     */
    private String extractFileNameFromUrl(String url, String contentDisposition) {
        String fileName = null;

        // 首先尝试从Content-Disposition中提取
        if (!TextUtils.isEmpty(contentDisposition)) {
            fileName = URLUtil.guessFileName(url, contentDisposition, null);
        }

        // 如果失败，从URL中提取
        if (TextUtils.isEmpty(fileName) || fileName.startsWith("download")) {
            try {
                String[] parts = url.split("/");
                String lastPart = parts[parts.length - 1];
                // 去除查询参数
                int queryIndex = lastPart.indexOf('?');
                if (queryIndex > 0) {
                    lastPart = lastPart.substring(0, queryIndex);
                }
                fileName = lastPart;
            } catch (Exception e) {
                fileName = "document.pdf";
            }
        }

        // 如果还是无效，使用默认文件名
        if (TextUtils.isEmpty(fileName)) {
            fileName = "court_document_" + System.currentTimeMillis() + ".pdf";
        }

        return fileName;
    }

    /**
     * 检查URL是否是PDF
     */
    private boolean isPdfUrl(String url) {
        if (TextUtils.isEmpty(url)) {
            return false;
        }

        String lowerUrl = url.toLowerCase();
        return lowerUrl.contains(".pdf") ||
                lowerUrl.contains("contenttype=application/pdf") ||
                lowerUrl.contains("mime=application/pdf");
    }

    /**
     * 格式化文件大小
     */
    private String formatFileSize(long size) {
        if (size < 1024) {
            return size + " B";
        } else if (size < 1024 * 1024) {
            return String.format("%.1f KB", size / 1024.0);
        } else if (size < 1024 * 1024 * 1024) {
            return String.format("%.1f MB", size / (1024.0 * 1024));
        } else {
            return String.format("%.1f GB", size / (1024.0 * 1024 * 1024));
        }
    }

    /**
     * 显示系统下载对话框
     */
    private void showSystemDownloadDialog(String url, String userAgent,
                                          String contentDisposition, String mimetype) {
        // 使用系统默认下载管理器
        try {
            Intent intent = new Intent(Intent.ACTION_VIEW);
            intent.setData(Uri.parse(url));
            startActivity(intent);
        } catch (Exception e) {
            Toast.makeText(this, "无法打开链接：" + e.getMessage(),
                    Toast.LENGTH_SHORT).show();
        }
    }

    /**
     * 扫描并下载页面中所有PDF（占位方法）
     */
    private void scanAndDownloadAllPdfs() {
        // 需要实现JavaScript注入来扫描页面中的PDF链接
        String js = "javascript:(function(){" +
                "var links = document.querySelectorAll('a');" +
                "var pdfLinks = [];" +
                "for(var i=0;i<links.length;i++){" +
                "if(links[i].href.includes('.pdf')){" +
                "pdfLinks.push(links[i].href);" +
                "}" +
                "}" +
                "return pdfLinks;" +
                "})()";

        webView.evaluateJavascript(js, value -> {
            Log.d(TAG, "Found PDF links: " + value);
            // 解析返回的链接并逐个下载
        });
    }

    /**
     * 设置文档下载监听器
     */
    public void setOnDocumentDownloadedListener(OnDocumentDownloadedListener listener) {
        this.documentListener = listener;
    }

    /**
     * 获取待处理的文档列表
     */
    public java.util.List<CourtDocument> getPendingDocuments() {
        return pendingDocuments;
    }

    @Override
    public void onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack();
        } else {
            super.onBackPressed();
        }
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (downloadExecutor != null && !downloadExecutor.isShutdown()) {
            downloadExecutor.shutdown();
        }
        if (downloadProgressDialog != null && downloadProgressDialog.isShowing()) {
            downloadProgressDialog.dismiss();
        }
        binding = null;
    }
}

package com.courassistant.java.parser;

import android.util.Log;

import com.courassistant.java.model.CourtCase;
import com.courassistant.java.model.CourtDocument;
import com.tom_roush.pdfbox.pdmodel.PDDocument;
import com.tom_roush.pdfbox.text.PDFTextStripper;

import java.io.File;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

/**
 * PDF解析器
 * 使用PDFBox提取PDF文本并解析法院传票信息
 */
public class PdfParser {

    private static final String TAG = "PdfParser";

    // 案号正则表达式（支持多种格式）
    private static final Pattern CASE_NO_PATTERN = Pattern.compile(
            "[(\\（]\\s*\\d{4}\\s*[)\\)]\\s*([\\u4e00-\\u9fa5]+)\\s*([\\u4e00-\\u9fa5]+)\\s*([\\u4e00-\\u9fa5]+)\\s*(\\d+)\\s*号"
    );

    // 开庭时间正则表达式
    private static final Pattern HEARING_DATE_PATTERN = Pattern.compile(
            "(?:开庭时间|庭审时间|时间)\\s*[:：]?\\s*(\\d{4})\\s*年\\s*(\\d{1,2})\\s*月\\s*(\\d{1,2})\\s*日\\s*(\\d{1,2})\\s*:\\s*(\\d{1,2})"
    );

    // 法院名称正则表达式
    private static final Pattern COURT_NAME_PATTERN = Pattern.compile(
            "([\\u4e00-\\u9fa5]+[\\u4e00-\\u9fa5]*法院)"
    );

    // 当事人正则表达式
    private static final Pattern PARTY_NAME_PATTERN = Pattern.compile(
            "(?:当事人|原告|被告|申请人|被申请人)\\s*[:：]?\\s*([\\u4e00-\\u9fa5]+|[\\u4e00-\\u9fa5]{2,4})"
    );

    // 开庭地点正则表达式
    private static final Pattern LOCATION_PATTERN = Pattern.compile(
            "(?:开庭地点|庭审地点|地点|地址)\\s*[:：]?\\s*([^\\n]{5,50})"
    );

    /**
     * 解析PDF文件
     * @param pdfFile PDF文件
     * @return 解析结果对象
     */
    public ParseResult parsePdf(File pdfFile) {
        ParseResult result = new ParseResult();
        result.setFilePath(pdfFile.getAbsolutePath());

        try {
            // 提取PDF文本
            String text = extractTextFromPdf(pdfFile);

            if (text == null || text.trim().isEmpty()) {
                result.setSuccess(false);
                result.setErrorMessage("PDF文本提取失败或内容为空");
                return result;
            }

            result.setExtractedText(text);

            // 判断是否是传票
            boolean isSummons = isSummons(text);
            result.setSummons(isSummons);

            if (!isSummons) {
                result.setSuccess(false);
                result.setErrorMessage("不是法院传票文档");
                result.setParseStatus(CourtDocument.PARSE_STATUS_NOT_SUMMONS);
                return result;
            }

            // 提取关键信息
            CourtCase courtCase = extractCourtCase(text);
            if (courtCase != null) {
                result.setCourtCase(courtCase);
                result.setSuccess(true);
                result.setParseStatus(CourtDocument.PARSE_STATUS_PARSED);
            } else {
                result.setSuccess(false);
                result.setErrorMessage("无法提取案件信息");
                result.setParseStatus(CourtDocument.PARSE_STATUS_FAILED);
            }

        } catch (Exception e) {
            Log.e(TAG, "解析PDF失败", e);
            result.setSuccess(false);
            result.setErrorMessage("解析失败：" + e.getMessage());
            result.setParseStatus(CourtDocument.PARSE_STATUS_FAILED);
        }

        return result;
    }

    /**
     * 从PDF中提取文本
     */
    private String extractTextFromPdf(File pdfFile) throws IOException {
        PDDocument document = null;
        try {
            document = PDDocument.load(pdfFile);
            PDFTextStripper stripper = new PDFTextStripper();

            // 设置文本提取参数
            stripper.setSortByPosition(true); // 按位置排序
            stripper.setLineSeparator("\n");  // 行分隔符

            String text = stripper.getText(document);
            return text.trim();

        } finally {
            if (document != null) {
                try {
                    document.close();
                } catch (IOException e) {
                    Log.e(TAG, "关闭PDF文档失败", e);
                }
            }
        }
    }

    /**
     * 判断是否是传票
     */
    private boolean isSummons(String text) {
        if (text == null || text.isEmpty()) {
            return false;
        }

        // 检查是否包含"传票"关键字
        if (text.contains("传票")) {
            return true;
        }

        // 检查是否包含多个法院文档特征
        int courtFeatureCount = 0;
        if (text.contains("开庭")) courtFeatureCount++;
        if (text.contains("案号")) courtFeatureCount++;
        if (text.contains("法院")) courtFeatureCount++;
        if (text.contains("当事人")) courtFeatureCount++;

        // 如果包含3个以上特征，判断为传票
        return courtFeatureCount >= 3;
    }

    /**
     * 提取案件信息
     */
    private CourtCase extractCourtCase(String text) {
        CourtCase courtCase = new CourtCase();

        try {
            // 提取案号
            String caseNo = extractCaseNo(text);
            if (caseNo != null && !caseNo.isEmpty()) {
                courtCase.setCaseNo(caseNo);
            }

            // 提取法院名称
            List<String> courtNames = extractCourtNames(text);
            if (!courtNames.isEmpty()) {
                courtCase.setCourtFullName(courtNames.get(0)); // 使用第一个匹配的法院名称
                // 简称可以用第一个法院名的简称
                courtCase.setCourtShortName(extractCourtShortName(courtNames.get(0)));
            }

            // 提取开庭时间
            Long hearingDate = extractHearingDate(text);
            if (hearingDate != null) {
                courtCase.setHearingDate(hearingDate);
            }

            // 提取当事人
            List<String> parties = extractParties(text);
            if (!parties.isEmpty()) {
                // 将所有当事人用逗号连接
                courtCase.setPartyName(String.join("、", parties));
            }

            // 提取开庭地点
            String location = extractLocation(text);
            if (location != null && !location.isEmpty()) {
                courtCase.setLocation(location);
            }

            // 验证是否提取到核心信息
            if (courtCase.getCaseNo() != null && courtCase.getHearingDate() > 0) {
                return courtCase;
            }

        } catch (Exception e) {
            Log.e(TAG, "提取案件信息失败", e);
        }

        return null;
    }

    /**
     * 提取案号
     */
    private String extractCaseNo(String text) {
        Matcher matcher = CASE_NO_PATTERN.matcher(text);
        if (matcher.find()) {
            return matcher.group(0);
        }

        // 尝试其他格式的案号
        Pattern alternativePattern = Pattern.compile("\\d{4}\\s*[年\\.]\\s*\\d+\\s*号");
        matcher = alternativePattern.matcher(text);
        if (matcher.find()) {
            return matcher.group(0);
        }

        return null;
    }

    /**
     * 提取法院名称列表
     */
    private List<String> extractCourtNames(String text) {
        List<String> courtNames = new ArrayList<>();
        Matcher matcher = COURT_NAME_PATTERN.matcher(text);

        while (matcher.find()) {
            String courtName = matcher.group(1);
            if (!courtNames.contains(courtName)) {
                courtNames.add(courtName);
            }
        }

        return courtNames;
    }

    /**
     * 提取法院简称
     */
    private String extractCourtShortName(String fullName) {
        if (fullName == null || fullName.isEmpty()) {
            return "";
        }

        // 简单的简称逻辑：去掉"市"、"省"等前缀
        String shortName = fullName
                .replace("人民法院", "")
                .replace("高级", "")
                .replace("中级", "")
                .replace("市", "")
                .replace("省", "");

        return shortName.isEmpty() ? fullName : shortName;
    }

    /**
     * 提取开庭时间
     */
    private Long extractHearingDate(String text) {
        Matcher matcher = HEARING_DATE_PATTERN.matcher(text);

        if (matcher.find()) {
            try {
                int year = Integer.parseInt(matcher.group(1));
                int month = Integer.parseInt(matcher.group(2));
                int day = Integer.parseInt(matcher.group(3));
                int hour = Integer.parseInt(matcher.group(4));
                int minute = Integer.parseInt(matcher.group(5));

                // 转换为时间戳
                java.util.Calendar calendar = java.util.Calendar.getInstance();
                calendar.set(year, month - 1, day, hour, minute, 0);
                calendar.set(java.util.Calendar.MILLISECOND, 0);

                return calendar.getTimeInMillis();
            } catch (Exception e) {
                Log.e(TAG, "解析开庭时间失败", e);
            }
        }

        // 尝试其他时间格式
        return null;
    }

    /**
     * 提取当事人
     */
    private List<String> extractParties(String text) {
        List<String> parties = new ArrayList<>();
        Matcher matcher = PARTY_NAME_PATTERN.matcher(text);

        while (matcher.find()) {
            String party = matcher.group(1);
            if (!parties.contains(party) && party.length() >= 2 && party.length() <= 4) {
                parties.add(party);
            }
        }

        // 如果没找到，尝试查找"原告"、"被告"等关键字后面的内容
        if (parties.isEmpty()) {
            Pattern simplePattern = Pattern.compile("(?:原告|被告)[：:]\\s*([\\u4e00-\\u9fa5]+)");
            matcher = simplePattern.matcher(text);
            while (matcher.find()) {
                String party = matcher.group(1);
                if (!parties.contains(party)) {
                    parties.add(party);
                }
            }
        }

        return parties;
    }

    /**
     * 提取开庭地点
     */
    private String extractLocation(String text) {
        Matcher matcher = LOCATION_PATTERN.matcher(text);

        if (matcher.find()) {
            String location = matcher.group(1).trim();
            // 清理可能的干扰字符
            location = location.replaceAll("\\s+", " ");
            return location;
        }

        // 尝试查找"第X法庭"、"第X审判庭"等
        Pattern alternativePattern = Pattern.compile("第\\s*\\d+\\s*(?:法庭|审判庭)");
        Matcher altMatcher = alternativePattern.matcher(text);
        if (altMatcher.find()) {
            return altMatcher.group(0).trim();
        }

        return null;
    }

    /**
     * 批量解析PDF文件
     * @param pdfFiles PDF文件列表
     * @return 解析结果列表
     */
    public List<ParseResult> parsePdfs(List<File> pdfFiles) {
        List<ParseResult> results = new ArrayList<>();

        for (File pdfFile : pdfFiles) {
            try {
                ParseResult result = parsePdf(pdfFile);
                results.add(result);
            } catch (Exception e) {
                Log.e(TAG, "批量解析失败：" + pdfFile.getName(), e);
                ParseResult errorResult = new ParseResult();
                errorResult.setFilePath(pdfFile.getAbsolutePath());
                errorResult.setSuccess(false);
                errorResult.setErrorMessage("解析异常：" + e.getMessage());
                results.add(errorResult);
            }
        }

        return results;
    }

    /**
     * 解析结果类
     */
    public static class ParseResult {
        private boolean success;
        private boolean summons;
        private String filePath;
        private String extractedText;
        private CourtCase courtCase;
        private String errorMessage;
        private int parseStatus;

        public boolean isSuccess() {
            return success;
        }

        public void setSuccess(boolean success) {
            this.success = success;
        }

        public boolean isSummons() {
            return summons;
        }

        public void setSummons(boolean summons) {
            this.summons = summons;
        }

        public String getFilePath() {
            return filePath;
        }

        public void setFilePath(String filePath) {
            this.filePath = filePath;
        }

        public String getExtractedText() {
            return extractedText;
        }

        public void setExtractedText(String extractedText) {
            this.extractedText = extractedText;
        }

        public CourtCase getCourtCase() {
            return courtCase;
        }

        public void setCourtCase(CourtCase courtCase) {
            this.courtCase = courtCase;
        }

        public String getErrorMessage() {
            return errorMessage;
        }

        public void setErrorMessage(String errorMessage) {
            this.errorMessage = errorMessage;
        }

        public int getParseStatus() {
            return parseStatus;
        }

        public void setParseStatus(int parseStatus) {
            this.parseStatus = parseStatus;
        }

        @Override
        public String toString() {
            return "ParseResult{" +
                    "success=" + success +
                    ", summons=" + summons +
                    ", filePath='" + filePath + '\'' +
                    ", errorMessage='" + errorMessage + '\'' +
                    ", parseStatus=" + parseStatus +
                    (courtCase != null ? ", caseNo=" + courtCase.getCaseNo() : "") +
                    '}';
        }
    }
}

package com.courassistant.java.ui;

import android.app.ProgressDialog;
import android.content.ActivityNotFoundException;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;
import android.util.Log;
import android.view.View;
import android.widget.Button;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.cardview.widget.CardView;

import com.courassistant.java.R;
import com.courassistant.java.databinding.ActivityPdfViewerBinding;
import com.courassistant.java.model.CourtCase;
import com.courassistant.java.model.CourtDocument;
import com.courassistant.java.parser.PdfParser;
import com.courassistant.java.utils.DateUtils;

import java.io.File;

/**
 * PDF查看器Activity
 * 用于显示已下载的PDF文档及解析结果
 */
public class PdfViewerActivity extends AppCompatActivity {

    private static final String TAG = "PdfViewerActivity";
    private static final int REQUEST_CODE_OPEN_PDF = 1001;

    private ActivityPdfViewerBinding binding;
    private PdfParser pdfParser;
    private CourtDocument document;
    private PdfParser.ParseResult parseResult;
    private ProgressDialog progressDialog;

    public static final String EXTRA_FILE_PATH = "file_path";
    public static final String EXTRA_DOCUMENT_ID = "document_id";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityPdfViewerBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        pdfParser = new PdfParser();
        setupProgressDialog();
        loadDocument();
        setupListeners();
    }

    /**
     * 设置进度对话框
     */
    private void setupProgressDialog() {
        progressDialog = new ProgressDialog(this);
        progressDialog.setMessage("正在解析PDF...");
        progressDialog.setProgressStyle(ProgressDialog.STYLE_SPINNER);
        progressDialog.setCancelable(false);
    }

    /**
     * 加载文档
     */
    private void loadDocument() {
        String filePath = getIntent().getStringExtra(EXTRA_FILE_PATH);

        if (filePath == null || filePath.isEmpty()) {
            Toast.makeText(this, "文档路径无效", Toast.LENGTH_SHORT).show();
            finish();
            return;
        }

        File file = new File(filePath);
        if (!file.exists()) {
            Toast.makeText(this, "文件不存在", Toast.LENGTH_SHORT).show();
            finish();
            return;
        }

        // 创建文档对象
        document = new CourtDocument();
        document.setFileName(file.getName());
        document.setFilePath(filePath);
        document.setFileSize(file.length());
        document.setFileType("PDF");

        // 显示文档信息
        displayDocumentInfo();
    }

    /**
     * 显示文档信息
     */
    private void displayDocumentInfo() {
        binding.tvFileName.setText(document.getFileName());
        binding.tvFileSize.setText(document.getFormattedFileSize());

        // 更新标题
        binding.toolbar.setTitle(new File(document.getFilePath()).getName());
    }

    /**
     * 设置按钮监听器
     */
    private void setupListeners() {
        // 返回按钮
        binding.btnBack.setOnClickListener(v -> {
            finish();
        });

        // 打开PDF按钮
        binding.btnOpenPdf.setOnClickListener(v -> {
            openPdfFile();
        });

        // 分享按钮
        binding.btnShare.setOnClickListener(v -> {
            sharePdfFile();
        });

        // 解析按钮
        binding.btnParse.setOnClickListener(v -> {
            parsePdf();
        });

        // 保存案件按钮
        binding.btnSaveCase.setOnClickListener(v -> {
            saveCase();
        });

        // 添加日历按钮
        binding.btnAddCalendar.setOnClickListener(v -> {
            addToCalendar();
        });
    }

    /**
     * 打开PDF文件
     */
    private void openPdfFile() {
        try {
            File file = new File(document.getFilePath());
            Uri uri = Uri.fromFile(file);

            Intent intent = new Intent(Intent.ACTION_VIEW);
            intent.setDataAndType(uri, "application/pdf");
            intent.setFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);

            startActivity(intent);
        } catch (ActivityNotFoundException e) {
            Toast.makeText(this, "未找到PDF阅读器", Toast.LENGTH_SHORT).show();
        } catch (Exception e) {
            Log.e(TAG, "打开PDF失败", e);
            Toast.makeText(this, "打开失败：" + e.getMessage(), Toast.LENGTH_SHORT).show();
        }
    }

    /**
     * 分享PDF文件
     */
    private void sharePdfFile() {
        try {
            File file = new File(document.getFilePath());
            Uri uri = Uri.fromFile(file);

            Intent intent = new Intent(Intent.ACTION_SEND);
            intent.setType("application/pdf");
            intent.putExtra(Intent.EXTRA_STREAM, uri);
            intent.putExtra(Intent.EXTRA_SUBJECT, document.getFileName());
            intent.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);

            startActivity(Intent.createChooser(intent, "分享PDF"));
        } catch (Exception e) {
            Log.e(TAG, "分享PDF失败", e);
            Toast.makeText(this, "分享失败：" + e.getMessage(), Toast.LENGTH_SHORT).show();
        }
    }

    /**
     * 解析PDF
     */
    private void parsePdf() {
        progressDialog.show();

        new Thread(() -> {
            try {
                File file = new File(document.getFilePath());
                parseResult = pdfParser.parsePdf(file);

                runOnUiThread(() -> {
                    progressDialog.dismiss();
                    displayParseResult();
                });
            } catch (Exception e) {
                Log.e(TAG, "解析PDF失败", e);
                runOnUiThread(() -> {
                    progressDialog.dismiss();
                    Toast.makeText(this, "解析失败：" + e.getMessage(),
                            Toast.LENGTH_LONG).show();
                });
            }
        }).start();
    }

    /**
     * 显示解析结果
     */
    private void displayParseResult() {
        if (parseResult == null) {
            Toast.makeText(this, "解析结果为空", Toast.LENGTH_SHORT).show();
            return;
        }

        // 显示解析状态
        updateParseStatus();

        if (parseResult.isSuccess()) {
            // 显示提取的文本
            if (parseResult.getExtractedText() != null) {
                binding.extractedTextCard.setVisibility(View.VISIBLE);
                binding.tvExtractedText.setText(parseResult.getExtractedText());
                binding.tvCharCount.setText(parseResult.getExtractedText().length() + " 字符");
            }

            // 显示案件信息
            if (parseResult.getCourtCase() != null) {
                displayCaseInfo(parseResult.getCourtCase());
            }

            // 启用保存按钮
            binding.btnSaveCase.setEnabled(true);
            binding.btnAddCalendar.setEnabled(parseResult.getCourtCase().getHearingDate() > 0);

        } else {
            // 解析失败
            binding.tvParseStatus.setText("解析状态：" + parseResult.getErrorMessage());
            binding.tvParseStatus.setTextColor(0xFFFF5252); // Error color

            // 仍然显示提取的文本（如果有）
            if (parseResult.getExtractedText() != null) {
                binding.extractedTextCard.setVisibility(View.VISIBLE);
                binding.tvExtractedText.setText(parseResult.getExtractedText());
            }
        }

        // 显示底部信息容器
        binding.infoContainer.setVisibility(View.VISIBLE);
    }

    /**
     * 更新解析状态
     */
    private void updateParseStatus() {
        String statusText;
        int statusColor;

        switch (parseResult.getParseStatus()) {
            case CourtDocument.PARSE_STATUS_PARSED:
                statusText = "解析状态：成功";
                statusColor = 0xFF4CAF50; // Green
                break;
            case CourtDocument.PARSE_STATUS_FAILED:
                statusText = "解析状态：失败";
                statusColor = 0xFFFF5252; // Red
                break;
            case CourtDocument.PARSE_STATUS_NOT_SUMMONS:
                statusText = "解析状态：非传票文档";
                statusColor = 0xFFFF9800; // Orange
                break;
            default:
                statusText = "解析状态：未知";
                statusColor = 0xFF757575; // Gray
        }

        binding.tvParseStatus.setText(statusText);
        binding.tvParseStatus.setTextColor(statusColor);

        // 更新文档的解析状态
        document.setParseStatus(parseResult.getParseStatus());
        document.setSummons(parseResult.isSummons());
    }

    /**
     * 显示案件信息
     */
    private void displayCaseInfo(CourtCase courtCase) {
        binding.caseInfoCard.setVisibility(View.VISIBLE);

        binding.tvCaseNo.setText(courtCase.getCaseNo() != null ? courtCase.getCaseNo() : "未提取");
        binding.tvCourtName.setText(courtCase.getCourtFullName() != null ?
                courtCase.getCourtFullName() : "未提取");

        // 格式化开庭时间
        if (courtCase.getHearingDate() > 0) {
            String formattedDate = DateUtils.formatFullDateTime(courtCase.getHearingDate());
            binding.tvHearingDate.setText(formattedDate);
        } else {
            binding.tvHearingDate.setText("未提取");
        }

        binding.tvLocation.setText(courtCase.getLocation() != null ?
                courtCase.getLocation() : "未提取");
    }

    /**
     * 保存案件到数据库
     */
    private void saveCase() {
        if (parseResult == null || parseResult.getCourtCase() == null) {
            Toast.makeText(this, "没有可保存的案件信息", Toast.LENGTH_SHORT).show();
            return;
        }

        // TODO: 实现保存到数据库的逻辑
        // 需要集成Room数据库和Repository

        Toast.makeText(this, "案件信息已保存", Toast.LENGTH_SHORT).show();

        // 禁用保存按钮，防止重复保存
        binding.btnSaveCase.setEnabled(false);
    }

    /**
     * 添加到日历
     */
    private void addToCalendar() {
        if (parseResult == null || parseResult.getCourtCase() == null) {
            Toast.makeText(this, "没有可添加的案件信息", Toast.LENGTH_SHORT).show();
            return;
        }

        CourtCase courtCase = parseResult.getCourtCase();

        if (courtCase.getHearingDate() <= 0) {
            Toast.makeText(this, "开庭时间无效", Toast.LENGTH_SHORT).show();
            return;
        }

        // TODO: 调用日历工具类添加事件
        // CalendarUtils.addCourtEvent(this, courtCase);

        Toast.makeText(this, "已添加到日历", Toast.LENGTH_SHORT).show();

        // 禁用添加按钮，防止重复添加
        binding.btnAddCalendar.setEnabled(false);
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (progressDialog != null && progressDialog.isShowing()) {
            progressDialog.dismiss();
        }
        binding = null;
    }
}

package com.courassistant.java.utils;

import android.content.Context;
import android.util.Log;

import com.courassistant.java.model.CourtDocument;

import java.io.File;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * PDF下载辅助类
 * 处理PDF去重、文件管理等
 */
public class PdfDownloadHelper {

    private static final String TAG = "PdfDownloadHelper";

    private final Context context;
    private final Map<String, CourtDocument> downloadedFiles;

    public PdfDownloadHelper(Context context) {
        this.context = context.getApplicationContext();
        this.downloadedFiles = new HashMap<>();
        loadExistingFiles();
    }

    /**
     * 加载已存在的文件记录
     */
    private void loadExistingFiles() {
        // TODO: 从数据库加载已下载的文件记录
        // 这里可以集成Repository来获取数据库中的文档列表
    }

    /**
     * 检查文件是否已下载（基于文件名和大小去重）
     * @param fileName 文件名
     * @param fileSize 文件大小
     * @return true表示已下载，false表示未下载
     */
    public boolean isAlreadyDownloaded(String fileName, long fileSize) {
        String dedupKey = fileName + "_" + fileSize;
        return downloadedFiles.containsKey(dedupKey);
    }

    /**
     * 检查文档是否已下载（基于CourtDocument对象）
     * @param document 文档对象
     * @return true表示已下载，false表示未下载
     */
    public boolean isAlreadyDownloaded(CourtDocument document) {
        return isAlreadyDownloaded(document.getFileName(), document.getFileSize());
    }

    /**
     * 添加下载记录
     * @param document 文档对象
     */
    public void addDownloadRecord(CourtDocument document) {
        String dedupKey = document.getDedupKey();
        downloadedFiles.put(dedupKey, document);
    }

    /**
     * 生成唯一的文件名
     * 如果文件名已存在，添加序号
     * @param originalFileName 原始文件名
     * @return 唯一的文件名
     */
    public String generateUniqueFileName(String originalFileName) {
        // 从原始文件名中分离基础名称和扩展名
        String baseName;
        String extension = "";

        int lastDotIndex = originalFileName.lastIndexOf('.');
        if (lastDotIndex > 0) {
            baseName = originalFileName.substring(0, lastDotIndex);
            extension = originalFileName.substring(lastDotIndex);
        } else {
            baseName = originalFileName;
        }

        // 检查文件名是否已存在
        String uniqueName = originalFileName;
        int counter = 1;

        while (isFileExist(uniqueName)) {
            uniqueName = baseName + "_" + counter + extension;
            counter++;
        }

        return uniqueName;
    }

    /**
     * 检查文件是否存在
     * @param fileName 文件名
     * @return true表示存在，false表示不存在
     */
    private boolean isFileExist(String fileName) {
        File pdfDir = getPdfStorageDir();
        File file = new File(pdfDir, fileName);
        return file.exists();
    }

    /**
     * 获取PDF存储目录
     * @return PDF存储目录
     */
    public File getPdfStorageDir() {
        File pdfDir = new File(context.getExternalFilesDir(null), "CourtPDFs");
        if (!pdfDir.exists()) {
            pdfDir.mkdirs();
        }
        return pdfDir;
    }

    /**
     * 扫描PDF目录，返回所有PDF文件
     * @return PDF文件列表
     */
    public List<File> scanPdfFiles() {
        List<File> pdfFiles = new ArrayList<>();
        File pdfDir = getPdfStorageDir();

        if (pdfDir.exists() && pdfDir.isDirectory()) {
            File[] files = pdfDir.listFiles();
            if (files != null) {
                for (File file : files) {
                    if (file.isFile() && file.getName().toLowerCase().endsWith(".pdf")) {
                        pdfFiles.add(file);
                    }
                }
            }
        }

        return pdfFiles;
    }

    /**
     * 清理重复的PDF文件
     * 保留最新的文件，删除旧文件
     * @return 清理的文件数量
     */
    public int cleanDuplicateFiles() {
        List<File> pdfFiles = scanPdfFiles();
        Map<String, List<File>> fileGroups = new HashMap<>();

        // 按文件大小分组
        for (File file : pdfFiles) {
            String key = file.getName() + "_" + file.length();
            if (!fileGroups.containsKey(key)) {
                fileGroups.put(key, new ArrayList<>());
            }
            fileGroups.get(key).add(file);
        }

        int cleanedCount = 0;

        // 删除重复文件，保留最新的
        for (Map.Entry<String, List<File>> entry : fileGroups.entrySet()) {
            List<File> group = entry.getValue();
            if (group.size() > 1) {
                // 按修改时间排序，保留最新的
                group.sort((f1, f2) -> Long.compare(f2.lastModified(), f1.lastModified()));

                // 删除除了第一个以外的所有文件
                for (int i = 1; i < group.size(); i++) {
                    File fileToDelete = group.get(i);
                    if (fileToDelete.delete()) {
                        cleanedCount++;
                        Log.d(TAG, "删除重复文件: " + fileToDelete.getName());
                    }
                }
            }
        }

        return cleanedCount;
    }

    /**
     * 获取下载统计信息
     * @return 统计信息字符串
     */
    public String getDownloadStatistics() {
        List<File> pdfFiles = scanPdfFiles();
        long totalSize = 0;

        for (File file : pdfFiles) {
            totalSize += file.length();
        }

        return String.format("已下载 %d 个PDF文件，总大小: %s",
                pdfFiles.size(),
                FileUtils.formatFileSize(totalSize));
    }

    /**
     * 从URL中提取文件名
     * @param url URL地址
     * @return 文件名
     */
    public static String extractFileNameFromUrl(String url) {
        if (url == null || url.isEmpty()) {
            return null;
        }

        try {
            String[] parts = url.split("/");
            String lastPart = parts[parts.length - 1];

            // 去除查询参数
            int queryIndex = lastPart.indexOf('?');
            if (queryIndex > 0) {
                lastPart = lastPart.substring(0, queryIndex);
            }

            // URL解码
            return java.net.URLDecoder.decode(lastPart, "UTF-8");
        } catch (Exception e) {
            Log.e(TAG, "从URL提取文件名失败", e);
            return null;
        }
    }

    /**
     * 验证PDF文件
     * @param file PDF文件
     * @return true表示有效，false表示无效
     */
    public static boolean isValidPdfFile(File file) {
        if (file == null || !file.exists() || !file.isFile()) {
            return false;
        }

        // 检查文件扩展名
        String name = file.getName().toLowerCase();
        if (!name.endsWith(".pdf")) {
            return false;
        }

        // 检查文件大小（PDF文件应该至少有1KB）
        if (file.length() < 1024) {
            return false;
        }

        // TODO: 可以添加PDF文件头检查（%PDF-）
        try {
            java.io.RandomAccessFile raf = new java.io.RandomAccessFile(file, "r");
            String header = raf.readLine();
            raf.close();
            return header != null && header.startsWith("%PDF-");
        } catch (Exception e) {
            Log.e(TAG, "验证PDF文件失败", e);
            return false;
        }
    }

    /**
     * 清空所有下载记录
     */
    public void clearAllRecords() {
        downloadedFiles.clear();
    }

    /**
     * 获取已下载文件数量
     * @return 已下载文件数量
     */
    public int getDownloadedCount() {
        return downloadedFiles.size();
    }

    /**
     * 获取所有已下载的文档
     * @return 已下载文档列表
     */
    public List<CourtDocument> getAllDownloadedDocuments() {
        return new ArrayList<>(downloadedFiles.values());
    }
}

