   184→    /**
   185→     * 计算文件的MD5哈希值
   186→     * 用于文件去重
   187→     */
   188→    public static String calculateMD5(File file) {
   189→        if (file == null || !file.exists()) {
   190→            return null;
   191→        }
   192→
   193→        MessageDigest md;
   194→        try {
   195→            md = MessageDigest.getInstance("MD5");
   196→        } catch (NoSuchAlgorithmException e) {
   197→            Log.e(TAG, "MD5算法不可用", e);
   198→            return null;
   199→        }
   200→
   201→        FileInputStream fis = null;
   202→        try {
   203→            fis = new FileInputStream(file);
   204→            byte[] buffer = new byte[8192];
   205→            int bytesRead;
   206→
   207→            while ((bytesRead = fis.read(buffer)) != -1) {
   208→                md.update(buffer, 0, bytesRead);
   209→            }
   210→
   211→            byte[] digest = md.digest();
   212→            StringBuilder sb = new StringBuilder();
   213→            for (byte b : digest) {
   214→                sb.append(String.format("%02x", b & 0xff));
   215→            }
   216→            return sb.toString();
   217→
   218→        } catch (IOException e) {
   219→            Log.e(TAG, "计算MD5失败", e);
   220→            return null;
   221→        } finally {
   222→            if (fis != null) {
   223→                try {
   224→                    fis.close();
   225→                } catch (IOException e) {
   226→                    Log.e(TAG, "关闭文件流失败", e);
   227→                }
   228→            }
   229→        }
   230→    }
