        return formatShortDate(System.currentTimeMillis());
    }

    /**
     * 将时间戳转换为完整日期时间字符串
     * @param timestamp 时间戳（毫秒）
     * @return 格式化后的字符串，如 "2024年03月15日 星期五 09:30"
     */
    public static String formatFullDateTime(long timestamp) {
        return formatTimestamp(timestamp, "yyyy年MM月dd日 E HH:mm");
    }
}

