/**
 * 法院WebView启动器
 * 用于启动PdfWebViewActivity并处理下载的PDF文档
 */
public class CourtWebViewLauncher {

    private static final String TAG = "CourtWebViewLauncher";

    /**
     * 启动WebView Activity加载法院网页
     * @param context 上下文
     * @param url 要加载的URL
     */
    public static void launchCourtWebView(Context context, String url) {
        Intent intent = new Intent(context, PdfWebViewActivity.class);
        intent.putExtra("url", url);
        context.startActivity(intent);
    }

    /**
     * 启动WebView Activity并设置文档监听器
     * @param context 上下文
     * @param url 要加载的URL
     * @param listener 文档下载监听器
     */
    public static void launchWithListener(Context context, String url,
                                         PdfWebViewActivity.OnDocumentDownloadedListener listener) {
        Intent intent = new Intent(context, PdfWebViewActivity.class);
        intent.putExtra("url", url);
        context.startActivity(intent);

        // 注意：这里需要在Activity中设置监听器
        // 可以通过单例模式或其他方式传递监听器
    }

    /**
     * 启动PDF查看器
     * @param context 上下文
     * @param filePath PDF文件路径
     */
    public static void launchPdfViewer(Context context, String filePath) {
        Intent intent = new Intent(context, PdfViewerActivity.class);
        intent.putExtra(PdfViewerActivity.EXTRA_FILE_PATH, filePath);
        context.startActivity(intent);
    }

    /**
     * 启动PDF查看器查看已下载的文档
     * @param context 上下文
     * @param document 文档对象
     */
    public static void launchPdfViewer(Context context, CourtDocument document) {
        if (document == null || document.getFilePath() == null) {
            Log.e(TAG, "文档路径为空");
            return;
        }

        Intent intent = new Intent(context, PdfViewerActivity.class);
        intent.putExtra(PdfViewerActivity.EXTRA_FILE_PATH, document.getFilePath());
        intent.putExtra(PdfViewerActivity.EXTRA_DOCUMENT_ID, document.getId());
        context.startActivity(intent);
    }

    /**
     * 使用示例代码
     */
    public static class UsageExample {
        private Context context;
        private PdfDownloadHelper downloadHelper;

        public UsageExample(Context context) {
            this.context = context;
            this.downloadHelper = new PdfDownloadHelper(context);
        }

        /**
         * 示例1：启动法院网页
         */
        public void example1_launchCourtWebsite() {
            String courtUrl = "https://www.chinacourt.org";
            CourtWebViewLauncher.launchCourtWebView(context, courtUrl);
        }

        /**
         * 示例2：处理下载的PDF
         */
        public void example2_handleDownloadedPdf() {
            PdfWebViewActivity.OnDocumentDownloadedListener listener = new PdfWebViewActivity.OnDocumentDownloadedListener() {
                @Override
                public void onDocumentDownloaded(CourtDocument document) {
                    // 检查是否已下载
                    if (downloadHelper.isAlreadyDownloaded(document)) {
                        Log.d(TAG, "PDF已下载，跳过：" + document.getFileName());
                        return;
                    }

                    // 添加到下载记录
                    downloadHelper.addDownloadRecord(document);

                    // TODO: 保存到数据库
                    // documentRepository.insert(document);

                    // TODO: 解析PDF
                    // PdfParser parser = new PdfParser();
                    // ParseResult result = parser.parsePdf(new File(document.getFilePath()));

                    Log.d(TAG, "PDF下载成功：" + document.getFileName());
                }
            };

            // 设置监听器（需要在Activity中设置）
            // ((PdfWebViewActivity) activity).setOnDocumentDownloadedListener(listener);
        }

        /**
         * 示例3：批量下载后的处理
         */
        public void example3_batchProcessing() {
            // 获取所有已下载的PDF文件
            java.util.List<File> pdfFiles = downloadHelper.scanPdfFiles();

            // 创建PDF解析器
            com.courassistant.java.parser.PdfParser parser = new com.courassistant.java.parser.PdfParser();

            // 批量解析
            java.util.List<com.courassistant.java.parser.PdfParser.ParseResult> results =
                    parser.parsePdfs(pdfFiles);

            // 处理解析结果
            for (com.courassistant.java.parser.PdfParser.ParseResult result : results) {
