import com.courassistant.java.utils.PdfDownloadHelper;

import java.io.File;
import java.util.List;

/**
 * PDF 下载和解析测试类
 * 用于演示和测试 PDF 相关功能
 */
public class PdfDownloadTest {

    private static final String TAG = "PdfDownloadTest";

    private final Context context;
    private final PdfDownloadHelper downloadHelper;
    private final PdfParser pdfParser;

    public PdfDownloadTest(Context context) {
        this.context = context;
        this.downloadHelper = new PdfDownloadHelper(context);
        this.pdfParser = new PdfParser();
    }

    /**
     * 测试1：扫描和显示 PDF 文件
     */
    public void test1_scanPdfs() {
        Log.d(TAG, "=== 测试1：扫描 PDF 文件 ===");

        List<File> pdfFiles = downloadHelper.scanPdfFiles();

        Log.d(TAG, "找到 " + pdfFiles.size() + " 个 PDF 文件：");
        for (File file : pdfFiles) {
            Log.d(TAG, "  - " + file.getName() + " (" + file.length() + " bytes)");
        }

        // 获取统计信息
        String stats = downloadHelper.getDownloadStatistics();
        Log.d(TAG, stats);
    }

    /**
     * 测试2：解析单个 PDF
     */
    public void test2_parseSinglePdf(String filePath) {
        Log.d(TAG, "=== 测试2：解析单个 PDF ===");
        Log.d(TAG, "文件路径：" + filePath);

        File pdfFile = new File(filePath);

        if (!pdfFile.exists()) {
            Log.e(TAG, "文件不存在：" + filePath);
            return;
        }

        // 验证 PDF 文件
        if (!PdfDownloadHelper.isValidPdfFile(pdfFile)) {
            Log.e(TAG, "不是有效的 PDF 文件");
            return;
        }

        // 解析 PDF
        PdfParser.ParseResult result = pdfParser.parsePdf(pdfFile);

        // 显示结果
        logParseResult(result);
    }

    /**
     * 测试3：批量解析 PDF
     */
    public void test3_batchParse() {
        Log.d(TAG, "=== 测试3：批量解析 PDF ===");

        List<File> pdfFiles = downloadHelper.scanPdfFiles();

        if (pdfFiles.isEmpty()) {
            Log.w(TAG, "没有找到 PDF 文件");
            return;
        }

        List<PdfParser.ParseResult> results = pdfParser.parsePdfs(pdfFiles);

        Log.d(TAG, "解析了 " + results.size() + " 个文件");

        int successCount = 0;
        int failCount = 0;
        int notSummonsCount = 0;

        for (PdfParser.ParseResult result : results) {
            if (result.isSuccess()) {
                successCount++;
            } else if (result.getParseStatus() == CourtDocument.PARSE_STATUS_NOT_SUMMONS) {
                notSummonsCount++;
            } else {
                failCount++;
            }

            logParseResult(result);
        }

        Log.d(TAG, "统计：成功 " + successCount + "，失败 " + failCount + "，非传票 " + notSummonsCount);
    }

    /**
     * 测试4：去重测试
     */
    public void test4_deduplication() {
        Log.d(TAG, "=== 测试4：去重测试 ===");

        // 模拟下载记录
        CourtDocument doc1 = new CourtDocument();
        doc1.setFileName("test.pdf");
        doc1.setFileSize(1024);

        CourtDocument doc2 = new CourtDocument();
        doc2.setFileName("test.pdf");
        doc2.setFileSize(1024);

        CourtDocument doc3 = new CourtDocument();
        doc3.setFileName("other.pdf");
        doc3.setFileSize(2048);

        // 测试去重
        Log.d(TAG, "doc1 和 doc2 相同？" + doc1.getDedupKey().equals(doc2.getDedupKey()));
        Log.d(TAG, "doc1 和 doc3 相同？" + doc1.getDedupKey().equals(doc3.getDedupKey()));

        // 测试下载辅助类
        downloadHelper.addDownloadRecord(doc1);
        boolean isDownloaded = downloadHelper.isAlreadyDownloaded(doc2);
        Log.d(TAG, "doc2 是否已下载？" + isDownloaded);
    }

    /**
     * 测试5：文件名生成测试
     */
    public void test5_fileNameGeneration() {
        Log.d(TAG, "=== 测试5：文件名生成测试 ===");

        String[] testNames = {
                "document.pdf",
                "传票.pdf",
                "test.pdf",
                "document.pdf"
        };

        for (String name : testNames) {
            String uniqueName = downloadHelper.generateUniqueFileName(name);
            Log.d(TAG, "原始：" + name + " -> 唯一：" + uniqueName);
        }
    }

    /**
     * 测试6：案件信息提取测试
     */
    public void test6_extractCaseInfo(String filePath) {
        Log.d(TAG, "=== 测试6：案件信息提取测试 ===");

        File pdfFile = new File(filePath);
        PdfParser.ParseResult result = pdfParser.parsePdf(pdfFile);

        if (result.isSuccess() && result.getCourtCase() != null) {
            CourtCase courtCase = result.getCourtCase();

            Log.d(TAG, "提取的案件信息：");
            Log.d(TAG, "  案号：" + courtCase.getCaseNo());
            Log.d(TAG, "  法院全称：" + courtCase.getCourtFullName());
            Log.d(TAG, "  法院简称：" + courtCase.getCourtShortName());
            Log.d(TAG, "  当事人：" + courtCase.getPartyName());
            Log.d(TAG, "  开庭时间：" + courtCase.getHearingDate());
            Log.d(TAG, "  开庭地点：" + courtCase.getLocation());

            // 格式化时间
            if (courtCase.getHearingDate() > 0) {
                String formattedDate = com.courassistant.java.utils.DateUtils.formatFullDateTime(
                        courtCase.getHearingDate());
                Log.d(TAG, "  格式化时间：" + formattedDate);
            }
        } else {
            Log.e(TAG, "提取失败：" + result.getErrorMessage());
        }
    }

    /**
     * 测试7：清理重复文件
     */
    public void test7_cleanDuplicates() {
        Log.d(TAG, "=== 测试7：清理重复文件 ===");

        int cleanedCount = downloadHelper.cleanDuplicateFiles();
        Log.d(TAG, "清理了 " + cleanedCount + " 个重复文件");
    }

    /**
     * 测试8：完整流程测试
     */
    public void test8_completeWorkflow() {
        Log.d(TAG, "=== 测试8：完整流程测试 ===");

        // 1. 扫描 PDF 文件
        test1_scanPdfs();

        // 2. 批量解析
        test3_batchParse();

        // 3. 清理重复文件
        test7_cleanDuplicates();

        // 4. 显示最终统计
        String finalStats = downloadHelper.getDownloadStatistics();
        Log.d(TAG, "最终统计：" + finalStats);
    }

    /**
     * 记录解析结果
     */
    private void logParseResult(PdfParser.ParseResult result) {
        if (result == null) {
            Log.e(TAG, "解析结果为空");
            return;
        }

        Log.d(TAG, "文件：" + new File(result.getFilePath()).getName());
        Log.d(TAG, "  成功：" + result.isSuccess());
        Log.d(TAG, "  是传票：" + result.isSummons());
        Log.d(TAG, "  解析状态：" + getParseStatusString(result.getParseStatus()));

        if (result.isSuccess() && result.getCourtCase() != null) {
            CourtCase courtCase = result.getCourtCase();
            Log.d(TAG, "  案号：" + courtCase.getCaseNo());
            Log.d(TAG, "  法院：" + courtCase.getCourtFullName());
            Log.d(TAG, "  时间：" + courtCase.getHearingDate());
        } else if (!result.isSuccess()) {
            Log.d(TAG, "  错误：" + result.getErrorMessage());
        }

        if (result.getExtractedText() != null) {
            int textLength = result.getExtractedText().length();
            Log.d(TAG, "  提取文本长度：" + textLength + " 字符");
        }
    }

    /**
     * 获取解析状态字符串
     */
    private String getParseStatusString(int status) {
        switch (status) {
            case CourtDocument.PARSE_STATUS_PENDING:
                return "待解析";
            case CourtDocument.PARSE_STATUS_PARSED:
                return "已解析";
            case CourtDocument.PARSE_STATUS_FAILED:
                return "解析失败";
            case CourtDocument.PARSE_STATUS_NOT_SUMMONS:
                return "非传票";
            default:
                return "未知";
        }
    }

    /**
     * 运行所有测试
     */
    public void runAllTests() {
        Log.d(TAG, "========================================");
        Log.d(TAG, "开始运行所有测试");
        Log.d(TAG, "========================================");

        test1_scanPdfs();
        test4_deduplication();
        test5_fileNameGeneration();
        // test2_parseSinglePdf(filePath); // 需要提供具体文件路径
        // test6_extractCaseInfo(filePath); // 需要提供具体文件路径
        test3_batchParse();
        test7_cleanDuplicates();

        Log.d(TAG, "========================================");
        Log.d(TAG, "所有测试完成");
        Log.d(TAG, "========================================");
    }

    /**
     * 运行特定测试
     */
    public void runTest(int testNumber) {
        switch (testNumber) {
            case 1:
                test1_scanPdfs();
                break;
            case 2:
                Log.d(TAG, "请提供文件路径");
                break;
            case 3:
                test3_batchParse();
                break;
            case 4:
                test4_deduplication();
                break;
            case 5:
                test5_fileNameGeneration();
                break;
            case 6:
                Log.d(TAG, "请提供文件路径");
                break;
            case 7:
                test7_cleanDuplicates();
                break;
            case 8:
                test8_completeWorkflow();
                break;
            default:
                Log.e(TAG, "未知测试编号：" + testNumber);
        }
    }
}

# WebView PDF 下载和解析功能 - 快速使用指南

## 快速开始

### 1. 启动 WebView 下载 PDF

```java
// 在你的 Activity 或 Fragment 中
Intent intent = new Intent(this, PdfWebViewActivity.class);
intent.putExtra("url", "https://www.chinacourt.org");
startActivity(intent);
```

### 2. 接收下载完成的 PDF

```java
public class MainActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        // 启动 WebView
        launchWebView();
    }

    private void launchWebView() {
        Intent intent = new Intent(this, PdfWebViewActivity.class);
        intent.putExtra("url", "https://court.example.com");

        // 使用 startActivityForResult 接收结果
        startActivityForResult(intent, REQUEST_CODE_WEBVIEW);
    }

    @Override
    protected void onActivityResult(int requestCode, int resultCode, Intent data) {
        super.onActivityResult(requestCode, resultCode, data);

        if (requestCode == REQUEST_CODE_WEBVIEW && resultCode == RESULT_OK) {
            // 处理下载的 PDF
            handleDownloadedPdfs();
        }
    }

    private void handleDownloadedPdfs() {
        PdfDownloadHelper helper = new PdfDownloadHelper(this);
        List<File> pdfFiles = helper.scanPdfFiles();

        // 解析所有 PDF
        PdfParser parser = new PdfParser();
        for (File file : pdfFiles) {
            PdfParser.ParseResult result = parser.parsePdf(file);
            if (result.isSuccess()) {
                // 保存案件信息
                saveCourtCase(result.getCourtCase());
            }
        }
    }
}
```

### 3. 查看已下载的 PDF

```java
// 启动 PDF 查看器
Intent intent = new Intent(this, PdfViewerActivity.class);
intent.putExtra(PdfViewerActivity.EXTRA_FILE_PATH, "/path/to/document.pdf");
startActivity(intent);
```

## 常见使用场景

### 场景1：从短信链接下载法院传票

```java
public class SmsReceiver extends BroadcastReceiver {

    @Override
    public void onReceive(Context context, Intent intent) {
        // 获取短信内容
        Bundle bundle = intent.getExtras();
        Object[] pdus = (Object[]) bundle.get("pdus");

        for (Object pdu : pdus) {
            SmsMessage sms = SmsMessage.createFromPdu((byte[]) pdu);

            // 检查是否包含法院链接
            if (containsCourtLink(sms.getMessageBody())) {
                String url = extractUrl(sms.getMessageBody());

                // 启动 WebView 下载
                Intent webIntent = new Intent(context, PdfWebViewActivity.class);
                webIntent.putExtra("url", url);
                webIntent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
                context.startActivity(webIntent);
            }
        }
    }
}
```

