        });
    }

    private String getParseStatusText(int status) {
        switch (status) {
            case CourtDocument.PARSE_STATUS_PARSED:
                return "已解析";
            case CourtDocument.PARSE_STATUS_FAILED:
                return "解析失败";
            case CourtDocument.PARSE_STATUS_NOT_SUMMONS:
                return "非传票";
            default:
                return "待解析";
        }
    }
}
```

