```

### 2. 自定义解析规则

```java
public class CustomPdfParser extends PdfParser {

    // 覆盖默认的案号匹配规则
    @Override
    protected String extractCaseNo(String text) {
        // 添加自定义的案号格式
        Pattern customPattern = Pattern.compile("YOUR_CUSTOM_REGEX");
        Matcher matcher = customPattern.matcher(text);

        if (matcher.find()) {
            return matcher.group(0);
        }

        // 如果自定义规则未匹配，使用父类方法
        return super.extractCaseNo(text);
    }
}
```

### 3. 自定义下载监听器

```java
public class MyDownloadListener implements PdfWebViewActivity.OnDocumentDownloadedListener {

    @Override
    public void onDocumentDownloaded(CourtDocument document) {
        // 1. 检查是否已下载
        PdfDownloadHelper helper = new PdfDownloadHelper(context);
        if (helper.isAlreadyDownloaded(document)) {
            return;
        }

        // 2. 添加到下载记录
        helper.addDownloadRecord(document);

        // 3. 立即解析
        PdfParser parser = new PdfParser();
        PdfParser.ParseResult result = parser.parsePdf(
            new File(document.getFilePath())
        );

        // 4. 处理解析结果
        if (result.isSuccess()) {
            // 保存案件信息
            saveCase(result.getCourtCase());

            // 显示通知
            showNotification("解析成功：" + result.getCourtCase().getCaseNo());
        }
    }
}
```

